text:
{
  "formal_minutes": {
    "project_code": "PUBLIC_MEETING_SMOKE",
    "meeting_title": "UI Theme Package Release Readiness",
    "confirmed_decisions": [
      {
        "item": "공개 릴리스 목표는 스모크 테스트가 통과하면 금요일 15:00 KST로 한다."
      },
      {
        "item": "packageName 불일치가 발생하면 먼저 패키지 설정을 확인하고, 계약 자체가 잘못된 경우에만 스크립트를 검토한다."
      }
    ],
    "rejected_proposals": [
      {
        "item": "Hara의 제안인 smoke-theme-pack.mjs에서 packageName 불일치를 무시하는 방식은 채택하지 않았다."
      }
    ],
    "internal_stretch_goals": [
      {
        "item": "수요일 공개 릴리스 제안은 내부 스트레치 목표로만 남겼다."
      },
      {
        "item": "README 설치 단계는 가능하면 목요일까지 검토하는 방향이 제안되었으나, 오너는 지정되지 않았다."
      }
    ],
    "risks": [
      {
        "item": "잘못된 tarball 경로는 릴리스를 지연시킬 수 있다."
      },
      {
        "item": "README 설치 단계가 오래되었으면 릴리스 노트가 사용자에게 잘못된 정보를 줄 수 있다."
      }
    ],
    "open_questions": [
      {
        "item": "최종 릴리스 승인 권한자는 누구인지 확정되지 않았다."
      },
      {
        "item": "릴리스 노트에 내부 수요일 스트레치 목표를 언급할지 결정되지 않았다."
      }
    ],
    "non_decisions": [
      {
        "item": "수요일 공개 릴리스는 최종 결정이 아니었고 내부 스트레치 목표 수준이었다."
      },
      {
        "item": "README 설치 단계 검토는 필요성이 언급되었지만 소유자와 확정 일정은 없었다."
      }
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "스모크 테스트를 다시 실행하고 결과를 공유한다.",
      "due": "Friday 10:00 KST",
      "status": "confirmed",
      "source_certainty": "confirmed"
    },
    {
      "owner": "Doyun",
      "task": "실패 triage note를 action_items.md에 작성한다.",
      "due": "Friday 12:00 KST",
      "status": "confirmed",
      "source_certainty": "confirmed"
    },
    {
      "owner": "Hara",
      "task": "Minjun이 스모크 결과를 올린 뒤 생성된 tarball 경로를 확인한다.",
      "due": "No exact deadline set",
      "status": "confirmed",
      "source_certainty": "confirmed"
    },
    {
      "owner": "Unassigned",
      "task": "README 설치 단계 검토 여부와 담당자를 확정한다.",
      "due": "Thursday if possible",
      "status": "open",
      "source_certainty": "inferred from discussion, but owner not assigned"
    }
  ],
  "followup_note": "다음 확인 대상은 스모크 테스트 결과, tarball 경로, README 설치 단계의 최신성, 그리고 최종 릴리스 승인권자이다. 고객명, 예산, 보안 사고, 장애, 법무 승인, 외부 파트너명은 이 회의 메모에 없으므로 절대 보완 추정하지 말아야 한다.",
  "non_invention_rules": [
    "고객명이나 외부 파트너명을 추가하지 않는다.",
    "예산 정보를 추정하거나 생성하지 않는다.",
    "보안 사고, 생산 장애, 법무 승인 요구를 만들어내지 않는다.",
    "소유자 미지정 항목에 임의의 담당자를 배정하지 않는다.",
    "명시되지 않은 마감 시각이나 날짜를 만들어내지 않는다.",
    "근거 없는 최종 승인권자, 릴리스 범위, 릴리스 노트를 추가하지 않는다."
  ]
}
